from pyspark.sql import SparkSession
from pyspark.sql.functions import avg

spark = SparkSession.builder.appName('GDELT Aggregation').getOrCreate()

df = spark.read.csv('data/gdelt/gdelt_events_sample.csv', header=True, inferSchema=True)

result = df.groupBy('action_country').agg(
    {'global_event_id': 'count', 'goldstein_scale': 'avg'}
).withColumnRenamed('count(global_event_id)', 'event_count')

result.write.format('org.apache.spark.sql.cassandra').options(
    table='gdelt_country_counts', keyspace='nl2pipeline'
).mode('overwrite').save()
